// // This module decodes a 4-bit binary input to a 2-bit output indicating the position of the least significant '1'. If the input is all zeros, the output is '11'.
module priority_encoder_4bit(
    input [3:0] in,   // 4-bit binary input.

    output [1:0] out  // 2-bit binary output.
);

assign out = (in[3]) ? 2'b11 :
             (in[2]) ? 2'b10 :
             (in[1]) ? 2'b01 :
             (in[0]) ? 2'b00 : 2'b00;

endmodule
